(function () {
  const STORAGE_KEY = 'glavani-cookie-consent';
  const banner = document.getElementById('cookie-banner');
  if (!banner) return;
  if (localStorage.getItem(STORAGE_KEY)) {
    banner.hidden = true;
    return;
  }
  banner.hidden = false;
  function accept() {
    localStorage.setItem(STORAGE_KEY, 'accepted');
    banner.hidden = true;
    document.dispatchEvent(new CustomEvent('glavani:analytics-consent'));
  }
  function decline() {
    localStorage.setItem(STORAGE_KEY, 'declined');
    banner.hidden = true;
  }
  document.getElementById('cookie-accept')?.addEventListener('click', accept);
  document.getElementById('cookie-decline')?.addEventListener('click', decline);
})();